export default {
  name: 'UpdateProfile',
  data() {
    return {
      valid: false,
      lastName: null,
      firstName: null,
      textRules: [
        // (v) => !!v || 'Bitte ausfüllen',
        (v) => (v && v.length >= 3) || 'mind. 3 Zeichen lang',
      ],
      requiredRule: [(v) => !!v || 'Bitte ausfüllen'],
      profession: null,
      password: '',
      hidePassword: true,
      password2: '',
      passwordRules: [
        (v) => !!v || 'Passwort nicht vergessen',
        (v) =>
          (!!v && v.length >= 8) ||
          'Passwort muss mindestens 8 Zeichen lang sein',
      ],
      passwordRules2: [
        (v) => !!v || 'Passwortüberprüfung nicht vergessen',
        (v) =>
          (!!v && v === this.password) || 'Passwörter müssen übereinstimmen',
      ],
      showError: false,
      loading: false,
      memberships: [],
      membership: undefined,
    }
  },
  async fetch() {
    this.memberships = (
      await this.$fire.firestore.collection('memberships').get()
    ).docs.map((doc) => doc.data())
    this.membership = this.memberships[0]
  },
  fetchOnServer: false,
  methods: {
    updateProfile() {
      this.loading = true
      this.$fire.auth.currentUser
        .updatePassword(this.password)
        .catch((e) => {
          // eslint-disable-next-line no-console
          console.error(e)
          this.showError = true
          this.loading = false
        })
        .then(() => {
          const createdUserData = {}
          if (this.membership.id === 'Coach') {
            createdUserData.public = {
              firstName: this.firstName,
              lastName: this.lastName,
              profession: this.profession,
              professionDuration: this.professionDuration,
              membership: this.membership.id,
            }
            createdUserData.private = {
              email: this.$fire.auth.currentUser.email,
            }
          } else {
            createdUserData.public = {
              membership: this.membership.id,
            }
            createdUserData.private = {
              firstName: this.firstName,
              lastName: this.lastName,
              email: this.$fire.auth.currentUser.email,
            }
          }
          return this.$store.dispatch(
            'modules/user/createFirebaseUser',
            createdUserData
          )
        })
    },
  },
}
